parameters.inputSchema:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "title": "MealNutritionData",
  "type": "object",
  "properties": {
    "mealName": {
      "type": "string",
      "description": "The name of the meal"
    },
    "calories": {
      "type": "number",
      "description": "Total calories in the meal"
    },
    "protein": {
      "type": "number",
      "description": "Grams of protein"
    },
    "carbs": {
      "type": "number",
      "description": "Grams of carbohydrates"
    },
    "fat": {
      "type": "number",
      "description": "Grams of fat"
    },
    "fiber": {
      "type": "number",
      "description": "Grams of dietary fiber"
    },
    "sugar": {
      "type": "number",
      "description": "Grams of sugar"
    },
    "sodium": {
      "type": "number",
      "description": "Milligrams of sodium"
    },
    "confidenceScore": {
      "type": "number",
      "minimum": 0,
      "maximum": 1,
      "description": "Model's confidence score (0 to 1) for the accuracy of the nutrition data"
    },
    "healthScore": {
      "type": "integer",
      "minimum": 1,
      "maximum": 5,
      "description": "Heuristic health score from 1 (least healthy) to 5 (most healthy)"
    }
  },
  "required": [
    "mealName",
    "calories",
    "protein",
    "carbs",
    "fat",
    "fiber",
    "sugar",
    "sodium",
    "confidenceScore",
    "healthScore"
  ],
  "additionalProperties": false
}
